{
  "recipes": [
    {
      "name": "Authentic Sichuan Mapo Tofu",
      "instructions": [
        "Cut the silken tofu into 2cm cubes and steep them in hot, lightly salted water to firm up.",
        "Heat oil in a wok and stir-fry the minced beef until dry, crispy, and brown.",
        "Add the finely minced ginger and garlic, followed by Pixian Doubanjiang and fermented black beans, frying until the oil turns red.",
        "Pour in a cup of water or stock, bring to a simmer, and gently slide in the drained tofu cubes.",
        "Simmer for 5 minutes, allowing the tofu to absorb the spicy flavors.",
        "Drizzle in cornstarch slurry in three stages to thicken the sauce perfectly.",
        "Finish with a drizzle of chili oil, green scallions, and a generous dusting of freshly ground Sichuan peppercorn powder."
      ],
      "required_ingredients": [
        {
          "name": "Silken tofu",
          "amount": "400g"
        },
        {
          "name": "Minced beef",
          "amount": "150g"
        },
        {
          "name": "Garlic",
          "amount": "3 cloves, minced"
        },
        {
          "name": "Ginger",
          "amount": "1 tbsp, minced"
        },
        {
          "name": "Pixian Doubanjiang (Chili Bean Paste)",
          "amount": "2 tbsp"
        },
        {
          "name": "Sichuan Peppercorn Powder",
          "amount": "1 tsp"
        },
        {
          "name": "Cornstarch",
          "amount": "1 tbsp"
        },
        {
          "name": "Scallions",
          "amount": "2 stalks, chopped"
        },
        {
          "name": "Chili Oil",
          "amount": "1 tbsp"
        }
      ],
      "missing_ingredients": [
