        "Cornstarch (approx. £1.00 at Sainsbury's)",
        "Sichuan Chili Oil (approx. £2.50 at Oseyo)"
      ]
    },
    {
      "name": "Sichuan Hot and Sour Beef Tofu Soup",
      "instructions": [
        "Finely chop the garlic and ginger, and cut the silken tofu into small, delicate matchsticks or small cubes.",
        "In a pot, heat a small amount of oil and stir-fry the minced beef with garlic and ginger until fragrant.",
        "Add beef or chicken stock and bring to a boil.",
        "Add light soy sauce, white pepper, and Chinese black vinegar for that signature spicy-sour kick.",
        "Gently slide in the silken tofu and simmer for 3 minutes.",
        "Thicken the soup slightly with cornstarch slurry, then slowly drizzle in a whisked egg if desired, or finish with chili oil and coriander."
      ],
      "required_ingredients": [
        {
          "name": "Silken tofu",
          "amount": "300g"
        },
        {
          "name": "Minced beef",
          "amount": "100g"
        },
        {
          "name": "Garlic",
          "amount": "2 cloves, minced"
        },
        {
          "name": "Ginger",
          "amount": "1 tsp, minced"
        },
        {
          "name": "Chinese Black Vinegar (Chinkiang)",
          "amount": "2 tbsp"
        },
        {
          "name": "White Pepper Powder",
          "amount": "1 tsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Chicken Stock",
          "amount": "500ml"
        },
        {
          "name": "Coriander",
          "amount": "for garnish"
        }
      ],
      "missing_ingredients": [
        "Chinkiang Black Vinegar (approx. £1.95 at Wing Yip)",
        "White Pepper Powder (approx. £1.50 at Sainsbury's)",
        "Light Soy Sauce (approx. £1.30 at Tesco)",
        "Chicken Stock Cubes (approx. £1.20 at Morrisons)",
        "Fresh Coriander (approx. £0.75 at Marks & Spencer)"
      ]
    },
    {
      "name": "Steamed Silken Tofu with Spicy Sichuan Minced Beef Topping",
      "instructions": [
        "Place the block of silken tofu on a heatproof plate and steam it for 5-7 minutes until hot. Carefully drain off any excess water.",
        "While steaming, heat oil in a pan and brown the minced beef until completely crispy.",
        "Add the minced ginger and garlic, followed by Sichuan chili flakes, soy sauce, and a touch of sugar.",
        "Stir-fry until the beef is fragrant and coated in the spicy oil.",
        "Spoon the hot, crispy, spicy minced beef mixture directly over the warm steamed tofu.",
        "Garnish with chopped spring onions and a splash of sesame oil."
      ],
      "required_ingredients": [
        {
          "name": "Silken tofu",
          "amount": "400g"
        },
        {
          "name": "Minced beef",
          "amount": "150g"
        },
        {
          "name": "Garlic",
          "amount": "2 cloves, minced"
        },
        {
          "name": "Ginger",
          "amount": "1 tsp, minced"
        },
        {
          "name": "Sichuan Chili Flakes",
          "amount": "1.5 tbsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Toasted Sesame Oil",
          "amount": "1 tsp"
        },
        {
          "name": "Spring Onions",
          "amount": "1 stalk, finely sliced"
        }
      ],
      "missing_ingredients": [
