  ]
}

{
  "recipes": [
    {
      "name": "Authentic Gong Bao Ji Ding (Kung Pao Chicken)",
      "instructions": [
        "Cut the chicken breasts into 1.5cm cubes. Marinate with a pinch of salt, 1 tsp soy sauce, and 1 tsp cornstarch.",
        "Prep the aromatics: slice the spring onions into white and green parts, finely chop the garlic and ginger, and cut dried chilies into halves.",
        "Mix the Kung Pao sauce in a small bowl: combine 1 tbsp Chinkiang black vinegar, 1 tbsp sugar, 1 tbsp soy sauce, 1 tbsp Shaoxing wine, and 1 tsp cornstarch.",
        "Heat oil in a wok over medium-high heat. Add the Sichuan peppercorns and dried chilies, frying until fragrant and slightly dark.",
        "Add the marinated chicken and stir-fry until it turns white.",
        "Toss in the ginger, garlic, and the white parts of the spring onions, frying for another minute.",
        "Pour in the sauce mixture and stir quickly until the sauce thickens and glazes the chicken.",
        "Stir in the green parts of the spring onions and optionally roasted peanuts, then serve hot."
      ],
      "required_ingredients": [
        {
          "name": "Chicken breasts",
          "amount": "300g"
        },
        {
          "name": "Spring onions",
          "amount": "4 stalks"
        },
        {
          "name": "Sichuan peppercorns",
          "amount": "1 tsp"
        },
        {
          "name": "Dried red Sichuan chilies",
          "amount": "10 pieces"
