{
  "recipes": [
    {
      "name": "Authentic Tomato Scrambled Eggs (番茄炒蛋)",
      "instructions": [
        "Beat the large free range eggs with a pinch of salt and a teaspoon of water to make them extra fluffy.",
        "Halve the cherry tomatoes.",
        "Heat 1 tablespoon of cooking oil in a wok or frying pan over high heat. Add the eggs, scramble quickly until just cooked but still soft, then immediately remove from the pan and set aside.",
        "Add another teaspoon of oil to the same pan. Stir-fry the cherry tomatoes until they soften and release their rich juices, about 3 minutes. Press them gently with your spatula to speed up the process.",
        "Season the tomatoes with sugar, salt, and optionally a splash of Shaoxing rice wine.",
        "Return the scrambled eggs to the pan. Toss quickly for 30 seconds to combine and allow the eggs to absorb the sweet and savory tomato juices.",
        "Stir in the chopped spring onions, turn off the heat, and serve immediately as a classic comforting dish."
      ],
      "required_ingredients": [
        {
          "name": "Large free range eggs",
          "amount": "3"
        },
        {
          "name": "Cherry tomatoes",
          "amount": "200g"
        },
        {
          "name": "Cooking oil",
          "amount": "1.5 tbsp"
        },
        {
          "name": "White sugar",
          "amount": "1 tsp"
        },
        {
          "name": "Fine sea salt",
          "amount": "0.5 tsp"
        },
        {
          "name": "Spring onions",
          "amount": "2 stalks"
        },
        {
          "name": "Shaoxing rice wine",
          "amount": "1 tsp"
        }
