        "White sugar (~£0.99 per bag at Tesco)",
        "Fine sea salt (~£0.95 at Sainsbury's)",
        "Shaoxing rice wine (~£2.50 at Loon Fung Chinatown)"
      ]
    },
    {
      "name": "Chinese Tomato Egg Drop Soup (番茄蛋花汤)",
      "instructions": [
        "Halve the cherry tomatoes. Finely chop the spring onions.",
        "Heat 1 teaspoon of sesame oil in a saucepan. Add half of the chopped spring onions and sauté for 30 seconds until fragrant.",
        "Add the cherry tomatoes and cook until they break down, forming a soft paste-like texture.",
        "Pour in 500ml of hot water or light chicken stock and bring to a boil. Simmer gently for 5 minutes.",
        "Stir in the cornstarch slurry (cornstarch mixed with 1 tbsp of cold water) to slightly thicken the soup base.",
        "Season with salt, white pepper, and a dash of light soy sauce.",
        "Slowly pour the beaten free range eggs into the simmering soup in a thin stream while stirring gently in one direction to create beautiful, silky egg ribbons.",
        "Drizzle with the remaining toasted sesame oil and garnish with the remaining spring onions before serving."
      ],
      "required_ingredients": [
        {
          "name": "Large free range eggs",
          "amount": "2"
        },
        {
          "name": "Cherry tomatoes",
          "amount": "150g"
        },
        {
          "name": "Toasted sesame oil",
          "amount": "1 tbsp"
        },
        {
          "name": "Spring onions",
          "amount": "2 stalks"
        },
        {
          "name": "Cornstarch / Cornflour",
          "amount": "1 tsp"
        },
        {
          "name": "Light soy sauce",
          "amount": "0.5 tsp"
        },
        {
          "name": "White pepper powder",
          "amount": "a pinch"
        },
        {
          "name": "Salt",
          "amount": "to taste"
        }
      ],
      "missing_ingredients": [
        "Toasted sesame oil (~£1.80 at Tesco)",
        "Spring onions (~£0.65 per bunch at Sainsbury's)",
        "Cornstarch / Cornflour (~£1.00 at Sainsbury's)",
        "Light soy sauce (~£1.50 at Marks & Spencer)",
        "White pepper powder (~£1.20 at Loon Fung Chinatown)",
        "Salt (~£0.95 at Sainsbury's)"
      ]
    },
    {
      "name": "Tomato Egg Stir-Fried Rice (番茄蛋炒饭)",
      "instructions": [
        "In a bowl, beat the large free range eggs with a pinch of salt.",
        "Halve the cherry tomatoes and finely mince the garlic and spring onions.",
        "Heat 1 tablespoon of cooking oil in a wok. Pour in the beaten eggs and scramble until just cooked. Remove and set aside.",
        "Heat another tablespoon of oil in the wok. Add minced garlic and the white parts of the spring onions, frying for 30 seconds until fragrant.",
        "Add the cherry tomatoes. Cook on high heat for 2 minutes until they soften but still hold their shape.",
        "Add the cold, leftover cooked jasmine rice, breaking up any clumps with your spatula. Stir constantly so the rice absorbs the tomato flavor.",
        "Add the light soy sauce, a pinch of salt, and a pinch of sugar. Stir-fry thoroughly.",
        "Return the scrambled eggs to the wok and toss to combine.",
        "Garnish with the green parts of the spring onions and serve immediately."
      ],
      "required_ingredients": [
        {
          "name": "Large free range eggs",
          "amount": "2"
        },
        {
          "name": "Cherry tomatoes",
          "amount": "150g"
        },
        {
          "name": "Leftover cooked jasmine rice",
          "amount": "2 cups (cold)"
        },
        {
          "name": "Garlic",
          "amount": "2 cloves"
        },
        {
          "name": "Spring onions",
          "amount": "2 stalks"
        },
        {
          "name": "Light soy sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Cooking oil",
          "amount": "2 tbsp"
        },
        {
          "name": "Salt & Sugar",
          "amount": "to taste"
        }
      ],
      "missing_ingredients": [
        "Leftover cooked jasmine rice (~£0.85 for a microwave pouch if needed at Tesco)",
        "Garlic (~£0.85 for a pack of 3 at Sainsbury's)",
        "Spring onions (~£0.65 per bunch at Sainsbury's)",
        "Light soy sauce (~£1.50 at Marks & Spencer)",
        "Cooking oil (~£2.20 per bottle at Tesco)"
      ]
    }
  ]
}

